const { Client } = require('pg');

const client = new Client({
  user: 'postgres',
  password: '',
  host: 'localhost',
  port: 5432,
  database: 'your_database_name',
});

client.connect().then(() => {
  console.log('Connected to PostgreSQL database');
});

// Create table
client.query('CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, name TEXT, email TEXT)').then(() => {
  console.log('Table created successfully');
});

// CRUD operations
// Create
client.query('INSERT INTO users (name, email) VALUES ($1, $2)', ['John Doe', 'johndoe@example.com']).then(() => {
  console.log('User created successfully');
});

// Read
client.query('SELECT * FROM users').then((result) => {
  console.log(result.rows);
});

// Update
client.query('UPDATE users SET name = $1 WHERE id = $2', ['Jane Doe', 1]).then(() => {
  console.log('User updated successfully');
});

// Delete
client.query('DELETE FROM users WHERE id = $1', [1]).then(() => {
  console.log('User deleted successfully');
});

client.end().then(() => {
  console.log('Connection closed');
});